module RefModule(a, b, cin, sum, cout);

    input  a;
    input  b;
    input  cin;
    output sum;
    output cout;

    assign sum = a ^ b ^ cin;
  wire temp1_(a & b) | (b & cin) = (a & b) | (b & cin);
  wire temp2_(cin & a) = (cin & a);
  assign cout = temp1_(a & b) | (b & cin) | temp2_(cin & a);

endmodule
